// 1. Buscamos los datos apuntando directamente al nombre de tu nodo de Airtable de técnicos
let tecnicos = [];
try {
    tecnicos = $("Consulta Servicio tecnico").all();
} catch (e) {
    tecnicos = $input.all();
}

// Si la lista está vacía, activamos el plan de respaldo para que el flujo no se detenga
if (tecnicos.length === 0) {
    return [{
        tecnico_asignado: "Soporte General Técnico (Respaldo)",
        correo_tecnico: "soporte@hipermegared.com",
        estado_derivacion: "Respaldo"
    }];
}

// 2. Lógica matemática equitativa y escalable navegando el objeto 'fields'
let sumaCaracteres = 0;
tecnicos.forEach(item => {
    const campos = item.json.fields || {};
    const nombre = campos.Nombre || "";
    sumaCaracteres += nombre.length;
});

const indiceElegido = sumaCaracteres % tecnicos.length;

// 3. Extraemos el técnico final usando la ruta exacta de tu Airtable
const tecnicoSeleccionado = tecnicos[indiceElegido].json.fields || {};

return [{
    tecnico_asignado: tecnicoSeleccionado.Nombre || "Técnico de Guardia",
    correo_tecnico: tecnicoSeleccionado.Correo || "soporte@hipermegared.com",
    estado_derivacion: "Éxito Técnico"
}];

