// 1. Apuntamos de forma directa al nodo de Airtable que busca al comercial
let asesores = [];
try {
    asesores = $("Consulta Asesor").all();
} catch (e) {
    asesores = $input.all();
}

// Si la lista está completamente vacía, activamos el respaldo de emergencia
if (asesores.length === 0) {
    return [{
        asesor_assigned: "Asesor Comercial (Respaldo)",
        correo_asesor: "ventas@hipermegared.com",
        estado_derivacion: "Respaldo"
    }];
}

// 2. Lógica matemática equitativa y escalable navegando el objeto 'fields'
let sumaCaracteres = 0;
asesores.forEach(item => {
    // Tu captura nos muestra que los datos vienen dentro de item.json.fields
    const campos = item.json.fields || {};
    const nombre = campos.Nombre || "";
    sumaCaracteres += nombre.length;
});

const indiceElegido = sumaCaracteres % asesores.length;

// 3. Extraemos el asesor final usando la ruta exacta de tu Airtable
const registroSeleccionado = asesores[indiceElegido].json.fields || {};

return [{
    asesor_asignado: registroSeleccionado.Nombre || "Asesor Comercial",
    correo_asesor: registroSeleccionado.Correo || "ventas@hipermegared.com",
    estado_derivacion: "Éxito"
}];

